#include <bits/stdc++.h>
using namespace std;
const int N=200005;
int n,a,b,c,dis[N],ans,ans2;
vector<int>  tree[N];
bool vis[N];
map<pair<int,int>,int> edge;
void make(int x,int y,int z)
{
    if(x>y) swap(x,y);
    int t=edge[make_pair(x,y)];
    if(t)
    {
        tree[z].push_back(t);
        tree[t].push_back(z);
    }
    else edge[make_pair(x,y)]=z;
}
void add(int num)
{
    cin>>a>>b>>c;
    make(a,b,num);
    make(a,c,num);
    make(b,c,num);
}
void dfs(int x,int fa)
{
    vis[x]=1;
    dis[x]=dis[fa]+1;
    if(dis[x]>ans)
    {
        ans2=x;
        ans=dis[x];
    }
    for(int j=0;j<tree[x].size();j++)
    {
        int t=tree[x][j];
        if(vis[t]) continue;
        dfs(t,x);
    }
}
int main()
{
    cin>>n;
    for(int i=1;i<=n-2;i++) add(i);
    dfs(1,0);
    ans=0;
    memset(dis,0,sizeof(dis));
    memset(vis,0,sizeof(vis));
    dfs(ans2,0);
    cout<<ans;
    return 0;
}
